class Solution {
    public String strWithout3a3b(int a, int b) {
        StringBuilder sb = new StringBuilder();
        while (a > 0 || b > 0) {
            if (a > b) {
                if (a - 1 > b) {
                    sb.append("aa");
                    a -= 2;
                } else {
                    sb.append('a');
                    a--;
                }
            } else {
                if (b - 1 > a) {
                    sb.append("bb");
                    b -= 2;
                } else {
                    sb.append('b');
                    b--;
                }
            }
        }
        return sb.toString();
    }
}
